def _sort_palette_colors(self, sort_palette):
    """
    Returns a copy of this "P"/"PA" mode image with its palette colors
    reordered, remapping pixel data to match. Used by :py:meth:`~PIL.Image.
    Image.quantize`.

    :param sort_palette: ``"brightness"`` to sort colors from darkest to
       lightest, or ``"rgb"`` to sort colors lexicographically by their
       channel values.
    """
    mode = self.palette.mode
    channels = len(mode)
    palette_data = self.palette.palette
    colors = [
        tuple(palette_data[i : i + channels])
        for i in range(0, len(palette_data), channels)
    ]

    # Only the entries actually referenced by a pixel are real colors;
    # the rest of the (fixed-size) palette buffer is unused zero-padding
    # and should be left as-is.
    used = max((pixel for _, pixel in self.getcolors(len(colors))), default=-1) + 1

    if sort_palette == "brightness":

        def sort_key(color):
            r, g, b = color[0], color[1], color[2]
            return 0.299 * r + 0.587 * g + 0.114 * b

    elif sort_palette == "rgb":

        def sort_key(color):
            return color

    else:
        raise ValueError(
            "sort_palette must be 'brightness', 'rgb', or None, "
            "not %r" % (sort_palette,)
        )

    order = sorted(range(used), key=lambda i: sort_key(colors[i]))
    remap = list(range(len(colors)))
    for new_index, old_index in enumerate(order):
        remap[old_index] = new_index

    im = self.point(remap)
    new_palette_data = (
        b"".join(bytes(colors[old_index]) for old_index in order)
        + palette_data[used * channels :]
    )
    if mode == "RGBA":
        rgb_data = bytes(
            byte for i, byte in enumerate(new_palette_data) if i % 4 != 3
        )
        im.im.putpalette("RGB", rgb_data)
        im.im.putpalettealphas(bytes(new_palette_data[3::4]))
    else:
        im.im.putpalette("RGB", new_palette_data)

    from . import ImagePalette

    im.palette = ImagePalette.ImagePalette(mode, new_palette_data)
    return im

def _quantize_to_error_threshold(
    self, colors, method, kmeans, dither, error_threshold
):
    """
    Quantizes with an increasing number of colors, stopping once the
    mean square error (MSE) between the original image and the
    quantized image is at or below ``error_threshold``, or ``colors``
    is reached. Used by :py:meth:`~PIL.Image.Image.quantize`.
    """
    from . import ImageChops, ImageStat

    original = self.convert("RGB") if self.mode != "RGB" else self

    def mse(candidate):
        diff = ImageChops.difference(original, candidate.convert("RGB"))
        stat = ImageStat.Stat(diff)
        return sum(band_rms ** 2 for band_rms in stat.rms) / len(stat.rms)

    lo, hi = 2, max(2, colors)
    best = self.quantize(hi, method, kmeans, dither=dither)
    if mse(best) <= error_threshold:
